import{_ as r,l as o,g as s,a0 as t}from"./chunks/framework.BtEyZ6Ww.js";const b=JSON.parse(`{"title":"HTTP errors","titleTemplate":"Troubleshooting - Guides","description":"Encountering HTTP errors? Here's what they mean and how to address them.","frontmatter":{"title":"HTTP errors","titleTemplate":"Troubleshooting - Guides","description":"Encountering HTTP errors? Here's what they mean and how to address them."},"headers":[],"relativePath":"docs/guides/troubleshooting/http-errors.md","filePath":"docs/guides/troubleshooting/http-errors.md","lastUpdated":1776895907000}`),a={name:"docs/guides/troubleshooting/http-errors.md"};function i(n,e,d,h,c,l){return o(),s("div",null,[...e[0]||(e[0]=[t('<h1 id="http-errors" tabindex="-1">HTTP errors <a class="header-anchor" href="#http-errors" aria-label="Permalink to &quot;HTTP errors&quot;">​</a></h1><p>Encountering HTTP errors? Here&#39;s what they mean and how to address them.</p><h2 id="_403-forbidden" tabindex="-1">403: Forbidden <a class="header-anchor" href="#_403-forbidden" aria-label="Permalink to &quot;403: Forbidden&quot;">​</a></h2><p>Possible reasons for this error:</p><ul><li>The selected source has Cloudflare protection. Check the <a href="/extensions-source/docs/guides/troubleshooting#cloudflare">Cloudflare guide</a> for solutions.</li><li>The source might be down, removed the series, or banned your IP. <blockquote><p>Open <a href="/extensions-source/docs/guides/troubleshooting#accessing-websites-via-webview">WebView</a> to confirm.</p></blockquote></li></ul><h2 id="_404-not-found" tabindex="-1">404: Not Found <a class="header-anchor" href="#_404-not-found" aria-label="Permalink to &quot;404: Not Found&quot;">​</a></h2><p>This error likely indicates that the source is down or the series has been removed. Use <a href="/extensions-source/docs/guides/troubleshooting#accessing-websites-via-webview"><strong>WebView</strong></a> to verify.</p><blockquote><p>Consider switching to a different source for the series.</p></blockquote><h2 id="_429-too-many-requests" tabindex="-1">429: Too Many Requests <a class="header-anchor" href="#_429-too-many-requests" aria-label="Permalink to &quot;429: Too Many Requests&quot;">​</a></h2><p>This error suggests the source temporarily banned your IP due to fast downloads/reads.</p><p><a href="https://github.com/fam007e/extensions-source/issues/new/choose" target="_blank" rel="noreferrer">Report the issue</a> to add rate limits and prevent future IP bans.</p><h2 id="_5xx-server-errors" tabindex="-1">5xx: Server Errors <a class="header-anchor" href="#_5xx-server-errors" aria-label="Permalink to &quot;5xx: Server Errors&quot;">​</a></h2><p>Errors like 500, 502, etc., indicate server-side issues on the source&#39;s end.</p><p><a href="/extensions-source/docs/guides/troubleshooting#accessing-websites-via-webview">Check the source in WebView</a> to check if it&#39;s down.</p><h2 id="_1006-1007-1008-1106-access-denied" tabindex="-1">1006, 1007, 1008, 1106: Access Denied <a class="header-anchor" href="#_1006-1007-1008-1106-access-denied" aria-label="Permalink to &quot;1006, 1007, 1008, 1106: Access Denied&quot;">​</a></h2><p>This error means a temporary IP ban by the source.</p><h2 id="_1020-access-denied" tabindex="-1">1020: Access Denied <a class="header-anchor" href="#_1020-access-denied" aria-label="Permalink to &quot;1020: Access Denied&quot;">​</a></h2><p>This error points to violating a firewall rule set by the site owner. The owner might have raised Cloudflare protection or blocked IPs from outside their country.</p>',18)])])}const p=r(a,[["render",i]]);export{b as __pageData,p as default};
